// permissionsUsage displays the usage of the permissions command and its
// subcommands.
func permissionsUsage() {
	fmt.Fprintln(os.Stderr, `The permissions service handles batch operations on note permissions.`)
	fmt.Fprintf(os.Stderr, "Usage:\n    %s [globalflags] permissions COMMAND [flags]\n\n", os.Args[0])
	fmt.Fprintln(os.Stderr, "COMMAND:")
	fmt.Fprintln(os.Stderr, `    batch-create: Creates one or more permissions on a note.`)
	fmt.Fprintln(os.Stderr, `    batch-delete: Deletes one or more permissions on a note.`)
	fmt.Fprintln(os.Stderr)
	fmt.Fprintln(os.Stderr, "Additional help:")
	fmt.Fprintf(os.Stderr, "    %s permissions COMMAND --help\n", os.Args[0])
}
func permissionsBatchCreateUsage() {
	// Header with flags
	fmt.Fprintf(os.Stderr, "%s [flags] permissions batch-create", os.Args[0])
	fmt.Fprint(os.Stderr, " -body JSON")
	fmt.Fprint(os.Stderr, " -note-id STRING")
	fmt.Fprintln(os.Stderr)

	// Description
	fmt.Fprintln(os.Stderr)
	fmt.Fprintln(os.Stderr, `Creates one or more permissions on a note.`)

	// Flags list
	fmt.Fprintln(os.Stderr, `    -body JSON: `)
	fmt.Fprintln(os.Stderr, `    -note-id STRING: The ID of the note.`)

	fmt.Fprintln(os.Stderr)
	fmt.Fprintln(os.Stderr, "Example:")
	fmt.Fprintf(os.Stderr, "    %s %s\n", os.Args[0], "permissions batch-create --body '{\n      \"requests\": [\n         {\n            \"email\": \"Id beatae aliquid consequuntur quisquam occaecati dolor.\",\n            \"role\": \"OWNER\"\n         },\n         {\n            \"email\": \"Id beatae aliquid consequuntur quisquam occaecati dolor.\",\n            \"role\": \"OWNER\"\n         },\n         {\n            \"email\": \"Id beatae aliquid consequuntur quisquam occaecati dolor.\",\n            \"role\": \"OWNER\"\n         },\n         {\n            \"email\": \"Id beatae aliquid consequuntur quisquam occaecati dolor.\",\n            \"role\": \"OWNER\"\n         }\n      ]\n   }' --note-id \"Sed ipsam dignissimos velit.\"")
}

